import{_ as e,o as t,c as r,ag as o}from"./chunks/framework.C9sp7nFj.js";const _=JSON.parse('{"title":"各国签证材料清单","description":"各国旅游签证所需材料清单汇总","frontmatter":{"title":"各国签证材料清单","description":"各国旅游签证所需材料清单汇总"},"headers":[],"relativePath":"knowledge/visa/materials.md","filePath":"knowledge/visa/materials.md","lastUpdated":null}'),i={name:"knowledge/visa/materials.md"};function l(n,a,s,d,h,c){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="各国签证材料清单" tabindex="-1">各国签证材料清单 <a class="header-anchor" href="#各国签证材料清单" aria-label="Permalink to &quot;各国签证材料清单&quot;">​</a></h1><h2 id="亚洲国家签证材料" tabindex="-1">亚洲国家签证材料 <a class="header-anchor" href="#亚洲国家签证材料" aria-label="Permalink to &quot;亚洲国家签证材料&quot;">​</a></h2><p>日本、韩国、泰国等亚洲国家的签证材料通常包括护照、申请表、照片、在职证明和银行流水，相对简洁。</p><h2 id="欧洲国家签证材料" tabindex="-1">欧洲国家签证材料 <a class="header-anchor" href="#欧洲国家签证材料" aria-label="Permalink to &quot;欧洲国家签证材料&quot;">​</a></h2><p>申根国家要求较严格，除基础材料外还需提供旅行保险、机票酒店订单、行程计划和近3-6个月的银行流水。</p><h2 id="美洲国家签证材料" tabindex="-1">美洲国家签证材料 <a class="header-anchor" href="#美洲国家签证材料" aria-label="Permalink to &quot;美洲国家签证材料&quot;">​</a></h2><p>美国签证需要DS-160表格确认页、面签预约信、详细的行程说明和充足的资产证明。加拿大签证类似，但无需面签。</p><h2 id="通用材料准备建议" tabindex="-1">通用材料准备建议 <a class="header-anchor" href="#通用材料准备建议" aria-label="Permalink to &quot;通用材料准备建议&quot;">​</a></h2><p>护照有效期需超过6个月，照片需符合各国具体要求。所有翻译件需规范，资金证明应体现稳定的收入来源。</p>',9)])])}const m=e(i,[["render",l]]);export{_ as __pageData,m as default};
